import{_ as r,c as i,o as n,a5 as t,j as a}from"./chunks/framework.Dtwt352Q.js";const p=JSON.parse('{"title":"v1.1.31：子 Agent 不占额度，新增复古主题","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.1.31.md","filePath":"changelog/v1.1.31.md","lastUpdated":1772014034000}'),o={name:"changelog/v1.1.31.md"};function l(s,e,h,d,c,g){return n(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="v1-1-31-子-agent-不占额度-新增复古主题" tabindex="-1">v1.1.31：子 Agent 不占额度，新增复古主题 <a class="header-anchor" href="#v1-1-31-子-agent-不占额度-新增复古主题" aria-label="Permalink to “v1.1.31：子 Agent 不占额度，新增复古主题”">​</a></h1><p><strong>发布日期</strong>：2026年01月22日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新带来了实打实的福利：子 Agent 的调用不再计入你的额度限制！同时增加了复古风格的 Gruvbox 主题和繁体中文支持。</p><hr><h2 id="重磅福利-子-agent-免额度" tabindex="-1">重磅福利：子 Agent 免额度 <a class="header-anchor" href="#重磅福利-子-agent-免额度" aria-label="Permalink to “重磅福利：子 Agent 免额度”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>现在，由主 Agent 启动的<strong>子 Agent 会话</strong>（Subagent sessions），将被标记为 <code>agent-initiated</code>，不再计入你的 API 使用额度限制（Quota Limits）。</p><h3 id="这意味着什么" tabindex="-1">这意味着什么？ <a class="header-anchor" href="#这意味着什么" aria-label="Permalink to “这意味着什么？”">​</a></h3><p>以前你可能担心叫几个帮手（子 Agent）会消耗太多额度。现在：</p><ul><li>你可以放心地让 AI 启动 <code>search</code> agent 去查资料。</li><li>或者是启动 <code>code-review</code> agent 来审查代码。</li><li>这些子任务的消耗将更加“宽容”（具体取决于你的额度策略，但通常意味着不占主额度或有单独配额）。</li></ul><h3 id="如何享受" tabindex="-1">如何享受？ <a class="header-anchor" href="#如何享受" aria-label="Permalink to “如何享受？”">​</a></h3><p>无需任何操作，升级到 v1.1.31 即可生效。</p><hr><h2 id="新外观-gruvbox-主题" tabindex="-1">新外观：Gruvbox 主题 <a class="header-anchor" href="#新外观-gruvbox-主题" aria-label="Permalink to “新外观：Gruvbox 主题”">​</a></h2><h3 id="什么是-gruvbox" tabindex="-1">什么是 Gruvbox？ <a class="header-anchor" href="#什么是-gruvbox" aria-label="Permalink to “什么是 Gruvbox？”">​</a></h3><p>Gruvbox 是一款非常经典的复古风格配色主题，以暖色调为主，对比度适中，长时间看代码不累眼。</p><h3 id="如何切换" tabindex="-1">如何切换？ <a class="header-anchor" href="#如何切换" aria-label="Permalink to “如何切换？”">​</a></h3><p>在 OpenCode Desktop 或 Web 版的设置中：</p><ol><li>打开 <strong>Settings</strong> (设置)</li><li>找到 <strong>Theme</strong> (主题)</li><li>选择 <strong>Gruvbox</strong></li></ol><hr><h2 id="语言支持-繁体中文" tabindex="-1">语言支持：繁体中文 <a class="header-anchor" href="#语言支持-繁体中文" aria-label="Permalink to “语言支持：繁体中文”">​</a></h2><h3 id="新增支持" tabindex="-1">新增支持 <a class="header-anchor" href="#新增支持" aria-label="Permalink to “新增支持”">​</a></h3><p>OpenCode 现在支持<strong>繁体中文</strong>界面了！同时，原来的 &quot;Chinese&quot; 选项已更名为 &quot;Chinese (Simplified)&quot;（简体中文），以便区分。</p><h3 id="如何设置" tabindex="-1">如何设置？ <a class="header-anchor" href="#如何设置" aria-label="Permalink to “如何设置？”">​</a></h3><ol><li>打开 <strong>Settings</strong></li><li>找到 <strong>Language</strong></li><li>选择 <strong>Traditional Chinese</strong></li></ol><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>经常使用 Task/Subagent 功能</td><td>✅ <strong>必须升级</strong> (省额度！)</td></tr><tr><td>喜欢复古配色</td><td>✅ 推荐升级</td></tr><tr><td>习惯繁体中文界面</td><td>✅ 推荐升级</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',31),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),t('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Mark subagent sessions as agent-initiated to exclude them from quota limits</li><li>Add chat.headers hook and update codex and copilot plugins to use it (thanks to @ananas-viber for catching)</li></ul><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h3><ul><li>Add Gruvbox theme to Web and App (@swolg)</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Add Traditional Chinese language support and rename Chinese to Chinese (Simplified) (@alexyaroshuk)</li><li>Add Russian language support (@alexyaroshuk)</li><li>Polish translations in app (@neriousy)</li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const u=r(o,[["render",l]]);export{p as __pageData,u as default};
